/* ── Feed styles ─────────────────────────────────── */
.feed {
  max-width: 640px;
  margin: 0 auto;
  padding: 32px 16px 64px;
  text-align: left;
}

.feed h1 {
  font-size: 32px;
  letter-spacing: -0.5px;
  margin-bottom: 24px;
  color: var(--text-h);
}

.feed-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.feed-item {
  background: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 20px 24px;
  box-shadow: 0 1px 4px rgba(0,0,0,0.05);
}

.feed-item h2 {
  font-size: 18px;
  margin: 0 0 6px;
  color: var(--text-h);
}

.feed-item p {
  color: var(--text);
  font-size: 15px;
  line-height: 1.6;
  margin: 0 0 10px;
}

.page-badge {
  display: inline-block;
  font-size: 12px;
  font-weight: 600;
  color: var(--accent);
  background: var(--accent-bg);
  border: 1px solid var(--accent-border);
  border-radius: 999px;
  padding: 2px 10px;
}

.load-more-container {
  margin-top: 32px;
  text-align: center;
}

.load-more-btn {
  background: var(--accent);
  color: #fff;
  border: none;
  border-radius: 8px;
  padding: 12px 32px;
  font-size: 16px;
  font-weight: 600;
  cursor: pointer;
  transition: opacity 0.2s;
}

.load-more-btn:hover:not(:disabled) {
  opacity: 0.85;
}

.load-more-btn:disabled {
  opacity: 0.55;
  cursor: not-allowed;
}

.end-message {
  color: var(--text);
  font-size: 14px;
}

.loading,
.error {
  text-align: center;
  margin-top: 60px;
  color: var(--text);
}
